func providerPreferenceForPolicy(cat *modelcatalog.Catalog, policy string) (string, error) {
	if policy == "" {
		return routing.ProviderPreferenceLocalFirst, nil
	}
	switch policy {
	case "code-medium":
		return "", fmt.Errorf("policy %q is deprecated; use --policy default or --min-power/--max-power", policy)
	case "code-high":
		return "", fmt.Errorf("policy %q is deprecated; use --policy smart or --min-power/--max-power", policy)
	}
	if cat == nil {
		return "", &ErrUnknownPolicy{Policy: policy}
	}
	if _, _, ok := policyForName(cat, policy); !ok {
		return "", &ErrUnknownPolicy{Policy: policy}
	}
	preference := providerPreferenceForPolicyName(policy)
	switch preference {
	case routing.ProviderPreferenceLocalOnly, routing.ProviderPreferenceSubscriptionOnly,
		routing.ProviderPreferenceLocalFirst, routing.ProviderPreferenceSubscriptionFirst:
		return preference, nil
	default:
		return "", fmt.Errorf("policy %q has unsupported provider preference %q", policy, preference)
	}
}

func routePowerPolicyForRequest(cat *modelcatalog.Catalog, req RouteRequest) RoutePowerPolicy {
	policy := RoutePowerPolicy{
		PolicyName: req.Policy,
		MinPower:   req.MinPower,
		MaxPower:   req.MaxPower,
	}
	if req.Policy == "" || cat == nil {
		return policy
	}
	policyEntry, policyName, ok := policyForName(cat, req.Policy)
	if !ok {
		return policy
	}
	policy.PolicyName = policyName
	if policyEntry.MinPower > 0 {
		if policy.MinPower == 0 || policyEntry.MinPower > policy.MinPower {
			policy.MinPower = policyEntry.MinPower
		}
	}
	if policyEntry.MaxPower > 0 {
		if policy.MaxPower == 0 || policyEntry.MaxPower < policy.MaxPower {
			policy.MaxPower = policyEntry.MaxPower
		}
	}
	return policy
}

func routePowerBoundsForRequest(req RouteRequest, policy RoutePowerPolicy) (int, int) {
	// Exact model pins remain exact model identity pins. The policy still
	// reports its effective power policy for evidence, but it does not widen
	// or override the caller's model.
	if req.Model != "" {
		return req.MinPower, req.MaxPower
	}
	return policy.MinPower, policy.MaxPower
}

package routehealth

import (
	"encoding/json"
	"os"
	"sync"
	"time"
)

// ProbeRecord records the most recent aliveness probe result for a provider endpoint.
type ProbeRecord struct {
	Provider         string    `json:"provider"`
	Endpoint         string    `json:"endpoint,omitempty"`
	LastProbeAt      time.Time `json:"last_probe_at"`
	LastProbeSuccess bool      `json:"last_probe_success"`
}

type probeKey struct {
	Provider string
	Endpoint string
}

// ProbeStore records per-provider aliveness probe results. It is safe for concurrent use.
type ProbeStore struct {
	mu      sync.RWMutex
	records map[probeKey]ProbeRecord
}

// NewProbeStore returns an empty probe store.
func NewProbeStore() *ProbeStore {
	return &ProbeStore{records: make(map[probeKey]ProbeRecord)}
}

// RecordProbe records an aliveness probe result for a provider/endpoint pair.
// Empty endpoint matches the provider's primary endpoint.
func (ps *ProbeStore) RecordProbe(provider, endpoint string, success bool, probeAt time.Time) {
	if provider == "" {
		return
	}
	if probeAt.IsZero() {
		probeAt = time.Now()
	}
	probeAt = probeAt.UTC()
	key := probeKey{Provider: provider, Endpoint: endpoint}
	ps.mu.Lock()
	defer ps.mu.Unlock()
	ps.records[key] = ProbeRecord{
		Provider:         provider,
		Endpoint:         endpoint,
		LastProbeAt:      probeAt,
		LastProbeSuccess: success,
	}
}

// LastProbe returns the most recent probe record for a provider/endpoint pair.
func (ps *ProbeStore) LastProbe(provider, endpoint string) (ProbeRecord, bool) {
	if ps == nil {
		return ProbeRecord{}, false
	}
	key := probeKey{Provider: provider, Endpoint: endpoint}
	ps.mu.RLock()
	defer ps.mu.RUnlock()
	r, ok := ps.records[key]
	return r, ok
}

// ProbeNeeded reports whether a provider/endpoint needs a new probe because its
// last probe is older than interval or has never been probed.
func (ps *ProbeStore) ProbeNeeded(provider, endpoint string, now time.Time, interval time.Duration) bool {
	if ps == nil {
		return false
	}
	r, ok := ps.LastProbe(provider, endpoint)
	if !ok {
		return true
	}
	return now.Sub(r.LastProbeAt) >= interval
}

// UnreachableProviders returns a map of provider name → probe time for providers
// whose most recent probe failed within ttl of now. Used to populate
// routing.Inputs.ProbeUnreachable.
func (ps *ProbeStore) UnreachableProviders(now time.Time, ttl time.Duration) map[string]time.Time {
	if ps == nil {
		return nil
	}
	if now.IsZero() {
		now = time.Now()
	}
	now = now.UTC()
	ps.mu.RLock()
	defer ps.mu.RUnlock()
	var out map[string]time.Time
	for _, r := range ps.records {
		if r.LastProbeSuccess {
			continue
		}
		if ttl > 0 && now.Sub(r.LastProbeAt) > ttl {
			continue
		}
		if out == nil {
			out = make(map[string]time.Time)
		}
		existing, ok := out[r.Provider]
		if !ok || r.LastProbeAt.After(existing) {
			out[r.Provider] = r.LastProbeAt
		}
	}
	return out
}

type persistedProbeStore struct {
	Records []ProbeRecord `json:"records"`
}

// Save persists probe records to a JSON file at path.
func (ps *ProbeStore) Save(path string) error {
	if ps == nil || path == "" {
		return nil
	}
	ps.mu.RLock()
	records := make([]ProbeRecord, 0, len(ps.records))
	for _, r := range ps.records {
		records = append(records, r)
	}
	ps.mu.RUnlock()
	data, err := json.MarshalIndent(persistedProbeStore{Records: records}, "", "  ")
	if err != nil {
		return err
	}
	return os.WriteFile(path, data, 0o644)
}

// Load reads probe records from a JSON file at path. Non-existent files are silently ignored.
func (ps *ProbeStore) Load(path string) error {
	if ps == nil || path == "" {
		return nil
	}
	data, err := os.ReadFile(path)
	if err != nil {
		if os.IsNotExist(err) {
			return nil
		}
		return err
	}
	var stored persistedProbeStore
	if err := json.Unmarshal(data, &stored); err != nil {
		return err
	}
	ps.mu.Lock()
	defer ps.mu.Unlock()
	for _, r := range stored.Records {
		if r.Provider == "" {
			continue
		}
		key := probeKey{Provider: r.Provider, Endpoint: r.Endpoint}
		existing, ok := ps.records[key]
		if !ok || r.LastProbeAt.After(existing.LastProbeAt) {
			ps.records[key] = r
		}
	}
	return nil
}

package routehealth

import (
	"sort"
	"strings"
	"sync"
	"time"
)

// DefaultLeaseTTL bounds how long an in-process sticky route lease may live
// without being refreshed.
const DefaultLeaseTTL = 5 * time.Minute

// LeaseKey identifies one sticky lease scope.
type LeaseKey struct {
	StickyKey string
}

// Lease describes one sticky endpoint assignment.
type Lease struct {
	Key         LeaseKey
	Provider    string
	Endpoint    string
	Model       string
	AcquiredAt  time.Time
	RefreshedAt time.Time
	ExpiresAt   time.Time
}

// LeaseInvalidation records why a lease was removed.
type LeaseInvalidation struct {
	Key        LeaseKey
	Provider   string
	Endpoint   string
	Model      string
	Reason     string
	RecordedAt time.Time
}

// LeaseStore owns in-process sticky route assignments. It is safe for
// concurrent use.
type LeaseStore struct {
	mu            sync.Mutex
	leases        map[LeaseKey]Lease
	invalidations map[LeaseKey]LeaseInvalidation
}

// NewLeaseStore returns an empty lease store.
func NewLeaseStore() *LeaseStore {
	return &LeaseStore{
		leases:        make(map[LeaseKey]Lease),
		invalidations: make(map[LeaseKey]LeaseInvalidation),
	}
}

// NormalizeLeaseKey trims whitespace from the sticky key.
func NormalizeLeaseKey(stickyKey string) LeaseKey {
	return LeaseKey{StickyKey: strings.TrimSpace(stickyKey)}
}

// Live returns the current lease for key when it has not expired.
func (s *LeaseStore) Live(now time.Time, key LeaseKey) (Lease, bool) {
	if s == nil {
		return Lease{}, false
	}
	now = normalizeLeaseNow(now)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	lease, ok := s.leases[key]
	if !ok {
		return Lease{}, false
	}
	return lease, true
}

// Acquire stores or refreshes a lease for key.
func (s *LeaseStore) Acquire(now time.Time, ttl time.Duration, key LeaseKey, provider, endpoint, model string) Lease {
	if s == nil {
		return Lease{}
	}
	now = normalizeLeaseNow(now)
	if ttl <= 0 {
		ttl = DefaultLeaseTTL
	}
	key = NormalizeLeaseKey(key.StickyKey)
	provider = strings.TrimSpace(provider)
	endpoint = strings.TrimSpace(endpoint)
	model = strings.TrimSpace(model)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)

	lease := Lease{
		Key:         key,
		Provider:    provider,
		Endpoint:    endpoint,
		Model:       model,
		AcquiredAt:  now,
		RefreshedAt: now,
		ExpiresAt:   now.Add(ttl),
	}
	if existing, ok := s.leases[key]; ok {
		if existing.Provider == provider && existing.Endpoint == endpoint && existing.Model == model {
			lease.AcquiredAt = existing.AcquiredAt
		}
	}
	s.leases[key] = lease
	delete(s.invalidations, key)
	return lease
}

// Invalidate removes the lease for key and records the reason.
func (s *LeaseStore) Invalidate(now time.Time, key LeaseKey, reason string) (LeaseInvalidation, bool) {
	if s == nil {
		return LeaseInvalidation{}, false
	}
	now = normalizeLeaseNow(now)
	key = NormalizeLeaseKey(key.StickyKey)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	lease, ok := s.leases[key]
	if !ok {
		return LeaseInvalidation{}, false
	}
	delete(s.leases, key)
	invalidation := LeaseInvalidation{
		Key:        key,
		Provider:   lease.Provider,
		Endpoint:   lease.Endpoint,
		Model:      lease.Model,
		Reason:     strings.TrimSpace(reason),
		RecordedAt: now,
	}
	s.invalidations[key] = invalidation
	return invalidation, true
}

// InvalidateEndpoint removes every lease for the provider/model scope that
// points at the named endpoint and records the supplied reason.
func (s *LeaseStore) InvalidateEndpoint(now time.Time, provider, endpoint, model, reason string) []LeaseInvalidation {
	if s == nil {
		return nil
	}
	now = normalizeLeaseNow(now)
	provider = strings.TrimSpace(provider)
	endpoint = strings.TrimSpace(endpoint)
	model = strings.TrimSpace(model)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	if len(s.leases) == 0 {
		return nil
	}
	var out []LeaseInvalidation
	for key, lease := range s.leases {
		if provider != "" && lease.Provider != provider {
			continue
		}
		if endpoint != "" && lease.Endpoint != endpoint {
			continue
		}
		if model != "" && lease.Model != model {
			continue
		}
		delete(s.leases, key)
		invalidation := LeaseInvalidation{
			Key:        key,
			Provider:   lease.Provider,
			Endpoint:   lease.Endpoint,
			Model:      lease.Model,
			Reason:     strings.TrimSpace(reason),
			RecordedAt: now,
		}
		s.invalidations[key] = invalidation
		out = append(out, invalidation)
	}
	return out
}

// LiveByScope returns the live leases for provider/model, ordered by sticky
// key for deterministic tests.
func (s *LeaseStore) LiveByScope(now time.Time, provider, model string) []Lease {
	if s == nil {
		return nil
	}
	now = normalizeLeaseNow(now)
	provider = strings.TrimSpace(provider)
	model = strings.TrimSpace(model)

	s.mu.Lock()
	defer s.mu.Unlock()
	s.expireLocked(now)
	if len(s.leases) == 0 {
		return nil
	}
	out := make([]Lease, 0, len(s.leases))
	for _, lease := range s.leases {
		if provider != "" && lease.Provider != provider {
			continue
		}
		if model != "" && lease.Model != model {
			continue
		}
		out = append(out, lease)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].Endpoint != out[j].Endpoint {
			return out[i].Endpoint < out[j].Endpoint
		}
		return out[i].Key.StickyKey < out[j].Key.StickyKey
	})
	return out
}

// LeaseCounts returns the live lease count per endpoint for provider/model.
func (s *LeaseStore) LeaseCounts(now time.Time, provider, model string) map[string]int {
	leases := s.LiveByScope(now, provider, model)
	if len(leases) == 0 {
		return nil
	}
	counts := make(map[string]int, len(leases))
	for _, lease := range leases {
		counts[lease.Endpoint]++
	}
	return counts
}

// LastInvalidation returns the most recent invalidation recorded for key.
func (s *LeaseStore) LastInvalidation(key LeaseKey) (LeaseInvalidation, bool) {
	if s == nil {
		return LeaseInvalidation{}, false
	}
	key = NormalizeLeaseKey(key.StickyKey)

	s.mu.Lock()
	defer s.mu.Unlock()
	invalidation, ok := s.invalidations[key]
	return invalidation, ok
}

func (s *LeaseStore) expireLocked(now time.Time) {
	for key, lease := range s.leases {
		if lease.ExpiresAt.IsZero() || lease.ExpiresAt.After(now) {
			continue
		}
		delete(s.leases, key)
		s.invalidations[key] = LeaseInvalidation{
			Key:        key,
			Provider:   lease.Provider,
			Endpoint:   lease.Endpoint,
			Model:      lease.Model,
			Reason:     "expired",
			RecordedAt: now,
		}

package routehealth

import (
	"sort"
	"strings"
	"sync"

	"github.com/easel/fizeau/internal/provider/utilization"
)

// UtilizationKey identifies one provider endpoint/model utilization sample.
type UtilizationKey struct {
	Provider string
	Endpoint string
	Model    string
}

// EndpointLoad is the normalized load signal used by routing.
type EndpointLoad struct {
	LeaseCount           int
	NormalizedLoad       float64
	UtilizationFresh     bool
	UtilizationSaturated bool
}

// UtilizationStore retains the most recent utilization sample for each
// provider endpoint. It is safe for concurrent use.
type UtilizationStore struct {
	mu      sync.RWMutex
	samples map[UtilizationKey]utilization.EndpointUtilization
}

// NewUtilizationStore returns an empty utilization store.
func NewUtilizationStore() *UtilizationStore {
	return &UtilizationStore{
		samples: make(map[UtilizationKey]utilization.EndpointUtilization),
	}
}

// NormalizeUtilizationKey trims whitespace from the utilization dimensions.
func NormalizeUtilizationKey(provider, endpoint, model string) UtilizationKey {
	return UtilizationKey{
		Provider: strings.TrimSpace(provider),
		Endpoint: strings.TrimSpace(endpoint),
		Model:    strings.TrimSpace(model),
	}
}

// Record stores the latest utilization sample for key.
func (s *UtilizationStore) Record(provider, endpoint, model string, sample utilization.EndpointUtilization) {
	if s == nil {
		return
	}
	key := NormalizeUtilizationKey(provider, endpoint, model)
	if key.Provider == "" && key.Endpoint == "" && key.Model == "" {
		return
	}
	if sample.Freshness == "" {
		sample.Freshness = utilization.FreshnessFresh
	}
	s.mu.Lock()
	defer s.mu.Unlock()
	if s.samples == nil {
		s.samples = make(map[UtilizationKey]utilization.EndpointUtilization)
	}
	s.samples[key] = cloneUtilization(sample)
}

// Sample returns the most recent utilization sample for provider/endpoint/model.
// When the endpoint-specific sample is unavailable, provider-wide samples are
// considered as a fallback so callers can still surface coarse utilization
// evidence without guessing at private probe internals.
func (s *UtilizationStore) Sample(provider, endpoint, model string) (utilization.EndpointUtilization, bool) {
	if s == nil {
		return utilization.EndpointUtilization{}, false
	}
	keyProvider := strings.TrimSpace(provider)
	keyEndpoint := strings.TrimSpace(endpoint)
	keyModel := strings.TrimSpace(model)

	s.mu.RLock()
	defer s.mu.RUnlock()
	if len(s.samples) == 0 {
		return utilization.EndpointUtilization{}, false
	}
	if sample, ok := s.samples[NormalizeUtilizationKey(keyProvider, keyEndpoint, keyModel)]; ok {
		return cloneUtilization(sample), true
	}
	if keyProvider != "" {
		if sample, ok := s.samples[NormalizeUtilizationKey(keyProvider, "", keyModel)]; ok {
			return cloneUtilization(sample), true
		}
	}
	return utilization.EndpointUtilization{}, false
}

// EndpointLoads returns the normalized load per endpoint for provider/model.
// Fresh utilization samples are combined with the supplied lease counts;
// stale or missing samples fall back to lease counts only.
func (s *UtilizationStore) EndpointLoads(provider, model string, leaseCounts map[string]int) map[string]EndpointLoad {
	if s == nil {
		return nil
	}
	keyProvider := strings.TrimSpace(provider)
	keyModel := strings.TrimSpace(model)

	s.mu.RLock()
	defer s.mu.RUnlock()
	if len(s.samples) == 0 && len(leaseCounts) == 0 {
		return nil
	}

	keys := make(map[string]struct{})
	for endpoint := range leaseCounts {
		keys[endpoint] = struct{}{}
	}
	for key := range s.samples {
		if keyProvider != "" && key.Provider != keyProvider {
			continue
		}
		if keyModel != "" && key.Model != keyModel {
			continue
		}
		if key.Endpoint != "" {
			keys[key.Endpoint] = struct{}{}
		}
	}
	if len(keys) == 0 {
		return nil
	}

	out := make(map[string]EndpointLoad, len(keys))
	for endpoint := range keys {
		leaseCount := leaseCounts[endpoint]
		load := EndpointLoad{
			LeaseCount:       leaseCount,
			NormalizedLoad:   float64(leaseCount),
			UtilizationFresh: false,
		}
		key := NormalizeUtilizationKey(keyProvider, endpoint, keyModel)
		sample, ok := s.samples[key]
		if !ok && keyProvider != "" {
			// Allow provider-wide samples to match when the caller does not
			// have a fully-qualified endpoint name.
			sample, ok = s.samples[NormalizeUtilizationKey(keyProvider, "", keyModel)]
		}
		if !ok || sample.Freshness != utilization.FreshnessFresh {
			out[endpoint] = load
			continue
		}
		normalized, saturated := normalizedLoadFromSample(sample)
		load.NormalizedLoad = float64(leaseCount) + normalized
		load.UtilizationFresh = true
		load.UtilizationSaturated = saturated
		out[endpoint] = load
	}

	return out
}

func normalizedLoadFromSample(sample utilization.EndpointUtilization) (float64, bool) {
	var active int
	var queued int
	if sample.ActiveRequests != nil {
		active = *sample.ActiveRequests
	}
	if sample.QueuedRequests != nil {
		queued = *sample.QueuedRequests
	}
	if sample.MaxConcurrency != nil && *sample.MaxConcurrency > 0 {
		total := active + queued
		pressure := float64(total) / float64(*sample.MaxConcurrency)
		if pressure < 0 {
			pressure = 0
		}
		return pressure, total >= *sample.MaxConcurrency
	}
	if sample.CacheUsage != nil {
		pressure := *sample.CacheUsage
		if pressure < 0 {
			pressure = 0
		}
		return pressure, pressure >= 1
	}
	total := active + queued
	if total < 0 {
		total = 0
	}
	return float64(total), false
}

func cloneUtilization(sample utilization.EndpointUtilization) utilization.EndpointUtilization {
	out := sample
	if sample.ActiveRequests != nil {
		out.ActiveRequests = utilization.Int(*sample.ActiveRequests)
	}
	if sample.QueuedRequests != nil {
		out.QueuedRequests = utilization.Int(*sample.QueuedRequests)
	}
	if sample.CacheUsage != nil {
		out.CacheUsage = utilization.Float64(*sample.CacheUsage)
	}
	if sample.MaxConcurrency != nil {
		out.MaxConcurrency = utilization.Int(*sample.MaxConcurrency)
	}
	return out
}

// EndpointLoadList returns a deterministic endpoint ordering for tests.
func EndpointLoadList(loads map[string]EndpointLoad) []string {
	if len(loads) == 0 {
		return nil
	}
	out := make([]string, 0, len(loads))
	for endpoint := range loads {
		out = append(out, endpoint)
	}
	sort.Strings(out)
	return out
}

package fizeau

import (
	"context"
	"sort"
	"strings"
	"time"

	"github.com/easel/fizeau/internal/modelsnapshot"
	"github.com/easel/fizeau/internal/routehealth"
	"github.com/easel/fizeau/internal/serverinstance"
)

// RouteStatus returns live routing state for configured providers/models.
// It is the operator dashboard view: cooldowns, recent decisions, and
// per-candidate health. Distinct from per-request ResolveRoute.
func (s *service) RouteStatus(ctx context.Context) (*RouteStatusReport, error) {
	s.ensurePrimaryQuotaRefresh(ctx, quotaRefreshAsync)
	report := &RouteStatusReport{
		GeneratedAt: time.Now(),
	}
	// ADR-006 §5: populate routing-quality over a recent window
	// (RouteStatusRoutingQualityWindow) regardless of whether a route
	// catalog is configured — the metric reflects Execute traffic, not
	// configured routes.
	if s != nil && s.routingQuality != nil {
		recent := s.routingQuality.snapshotRecent(RouteStatusRoutingQualityWindow, time.Time{})
		report.RoutingQuality = computeRoutingQualityMetricsFromRecords(recent)
	}
	if s == nil || s.opts.ServiceConfig == nil {
		return report, nil
	}

	cat := serviceRoutingCatalog()
	_, snapshot := s.buildRoutingInputsWithCatalog(ctx, cat, modelsnapshot.RefreshBackground)
	cooldown := s.routeAttemptTTL()
	activeAttempts := s.activeRouteAttempts(report.GeneratedAt, cooldown)
	successRate, latencyMS := s.routeMetricSignals(report.GeneratedAt, cooldown)
	report.SnapshotCapturedAt = snapshot.AsOf
	report.Routes = s.routeStatusEntriesFromSnapshot(snapshot, activeAttempts, successRate, latencyMS, cooldown)
	return report, nil
}

func (s *service) routeStatusEntriesFromSnapshot(snapshot modelsnapshot.ModelSnapshot, activeAttempts []routehealth.Record, successRate, latencyMS map[string]float64, cooldown time.Duration) []RouteStatusEntry {
	if len(snapshot.Models) == 0 {
		return nil
	}
	grouped := make(map[string][]modelsnapshot.KnownModel)
	for _, row := range snapshot.Models {
		if harness := strings.TrimSpace(row.Harness); harness != "" && harness != "fiz" {
			continue
		}
		if s.opts.ServiceConfig != nil {
			if _, ok := s.opts.ServiceConfig.Provider(row.Provider); !ok {
				continue
			}
		}
		model := strings.TrimSpace(row.ID)
		if model == "" {
			continue
		}
		grouped[model] = append(grouped[model], row)
	}
	if len(grouped) == 0 {
		return nil
	}
	keys := make([]string, 0, len(grouped))
	for model := range grouped {
		keys = append(keys, model)
	}
	sort.Strings(keys)

	entries := make([]RouteStatusEntry, 0, len(keys))
	for _, model := range keys {
		rows := grouped[model]
		sort.Slice(rows, func(i, j int) bool {
			if rows[i].Provider != rows[j].Provider {
				return rows[i].Provider < rows[j].Provider
			}
			if rows[i].EndpointName != rows[j].EndpointName {
				return rows[i].EndpointName < rows[j].EndpointName
			}
			if rows[i].EndpointBaseURL != rows[j].EndpointBaseURL {
				return rows[i].EndpointBaseURL < rows[j].EndpointBaseURL
			}
			if rows[i].ServerInstance != rows[j].ServerInstance {
				return rows[i].ServerInstance < rows[j].ServerInstance
			}
			return rows[i].ID < rows[j].ID
		})
		entry := RouteStatusEntry{Model: model, Strategy: "auto"}
		if cached, ok := s.lookupRouteDecision(model); ok {
			entry.LastDecision = cached.decision
			entry.LastDecisionAt = cached.at
			entry.SelectedEndpoint = cached.decision.Endpoint
			entry.SelectedServerInstance = cached.decision.ServerInstance
			entry.Sticky = cached.decision.Sticky
		}
		entry.Candidates = make([]RouteCandidateStatus, 0, len(rows))
		for i, row := range rows {
			provider := strings.TrimSpace(row.Provider)
			endpoint := strings.TrimSpace(row.EndpointName)
			serverID := serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance)
			candidate := RouteCandidateStatus{
				Provider:                      provider,
				Endpoint:                      endpoint,
				Model:                         model,
				ServerInstance:                serverID,
				Billing:                       row.Billing,
				ActualCashSpend:               row.ActualCashSpend,
				EffectiveCost:                 row.EffectiveCost,
				EffectiveCostSource:           row.EffectiveCostSource,
				Priority:                      len(rows) - i,
				Healthy:                       true,
				SourceStatus:                  string(row.Status),
				AutoRoutable:                  row.AutoRoutable,
				ExactPinOnly:                  row.ExactPinOnly,
				ExclusionReason:               row.ExclusionReason,
				Power:                         row.Power,
				ContextLength:                 row.ContextWindow,
				CostInputPerMTok:              row.CostInputPerM,
				CostOutputPerMTok:             row.CostOutputPerM,
				RecentLatencyMS:               float64(row.RecentP50Latency.Milliseconds()),
				ProviderReliabilityRate:       routeStatusMetricValue(successRate, provider, endpoint, model),
				QuotaRemaining:                row.QuotaRemaining,
				SnapshotCapturedAt:            snapshot.AsOf,
				HealthFreshnessAt:             row.HealthFreshnessAt.UTC(),
				HealthFreshnessSource:         row.HealthFreshnessSource,
				QuotaFreshnessAt:              row.QuotaFreshnessAt.UTC(),
				QuotaFreshnessSource:          row.QuotaFreshnessSource,
				ModelDiscoveryFreshnessAt:     row.DiscoveredAt.UTC(),
				ModelDiscoveryFreshnessSource: string(row.DiscoveredVia),
			}
			if attemptCooldown := routeAttemptCandidateCooldown(activeAttempts, provider, endpoint, model, cooldown); attemptCooldown != nil {
				candidate.Cooldown = attemptCooldown
			}
			if candidate.Cooldown != nil {
				candidate.Healthy = false
			}
			if candidate.RecentLatencyMS == 0 {
				candidate.RecentLatencyMS = routeStatusMetricValue(latencyMS, provider, endpoint, model)
			}
			entry.Candidates = append(entry.Candidates, candidate)
		}
		entries = append(entries, entry)
	}
	return entries
}

func routeStatusMetricValue(values map[string]float64, provider, endpoint, model string) float64 {
	if len(values) == 0 {
		return 0
	}
	key := routeStatusMetricKey(provider, endpoint, model)
	if value, ok := values[key]; ok {
		return value
	}
	if endpoint != "" {
		if value, ok := values[routeStatusMetricKey(provider, "", model)]; ok {
			return value
		}
	}
	return 0
}

func routeStatusMetricKey(provider, endpoint, model string) string {
	return routehealth.ProviderModelKey(routehealth.Key{
		Provider: provider,
		Endpoint: endpoint,
		Model:    model,
	})
}

func routeAttemptCandidateCooldown(records []routehealth.Record, providerName, endpointName, model string, cooldown time.Duration) *CooldownState {
	var newest *routehealth.Record
	for i := range records {
		record := &records[i]
		if record.Key.Provider == "" {
			continue
		}
		recordProvider := record.Key.Provider
		recordEndpoint := record.Key.Endpoint
		if base, ep, ok := splitEndpointProviderRef(recordProvider); ok {
			recordProvider = base
			if recordEndpoint == "" {
				recordEndpoint = ep
			}
		}
		if providerName != "" && recordProvider != providerName {
			continue
		}
		if endpointName != "" && recordEndpoint != "" && recordEndpoint != endpointName {
			continue
		}
		if record.Key.Model != "" && model != "" && record.Key.Model != model {
			continue
		}
		if newest == nil || record.RecordedAt.After(newest.RecordedAt) {
			newest = record
		}
	}
	if newest == nil {
		return nil
	}
	return routeAttemptCooldown(*newest, cooldown)
}

// cacheRouteDecision stores a ResolveRoute result keyed by routeKey.
// Called by ResolveRoute after a successful resolution.
func (s *service) cacheRouteDecision(routeKey string, dec *RouteDecision) {
	if routeKey == "" || dec == nil {
		return
	}
	s.lastDecisionMu.Lock()
	defer s.lastDecisionMu.Unlock()
	if s.lastDecisionCache == nil {
		s.lastDecisionCache = make(map[string]lastDecisionEntry)
	}
	s.lastDecisionCache[routeKey] = lastDecisionEntry{
		decision: dec,

	// are rejected pre-dispatch with CorrelationIDNormalizationError.
	CorrelationID string
}

// StallPolicy bounds how long the agent will spin without making progress
// before terminating with Status="stalled". A nil policy resolves to the
// default in service_execute.go.
type StallPolicy struct {
	MaxReadOnlyToolIterations int // 0 = disabled
}

// service is the concrete FizeauService implementation.
type service struct {
	opts     ServiceOptions
	registry *harnesses.Registry
	// harnessInstances holds the registered Harness implementation for
	// each known harness name. The refresh scheduler iterates over this
	// map, type-asserting each instance to the optional CONTRACT-004
	// sub-interfaces (QuotaHarness, AccountHarness). harnessByName is
	// the consultation seam.
	harnessInstances map[string]harnesses.Harness
	refreshScheduler *refreshScheduler
	hub              *serviceimpl.SessionHub

	// lastDecisionMu guards lastDecisionCache.
	lastDecisionMu sync.RWMutex
	// lastDecisionCache maps route key → (decision, time). Populated by
	// ResolveRoute; read by RouteStatus.
	lastDecisionCache map[string]lastDecisionEntry

	routeHealth      *routehealth.Store
	routeLeases      *routehealth.LeaseStore
	routeUtilization *routehealth.UtilizationStore

	// catalog is the service-scope model-catalog cache. Populated lazily
	// on first use by routing + chat paths; shared across requests so the
	// same endpoint isn't probed per-dispatch during a drain. See
	// service_catalog_cache.go.
	catalog *catalogCache

	// routingQuality records routing-quality observations (ADR-006 §5).
	// Populated by Execute on every request and read by RouteStatus and
	// UsageReport.
	routingQuality *routingQualityStore

	// providerQuota is the per-provider quota state machine. Routing reads
	// the projected exhausted set on every Resolve so quota_exhausted
	// providers are excluded from candidate selection.
	providerQuota *ProviderQuotaStateStore

	// providerBurnRate observes per-provider token consumption against the
	// operator-configured daily_token_budget and pre-emptively transitions
	// providers into quota_exhausted when local burn-rate predicts the
	// budget will be exceeded before the next UTC daily reset.
	providerBurnRate *ProviderBurnRateTracker

	// providerProbe stores aliveness probe results for configured non-cloud
	// providers. Populated by startup and periodic background probes.
	providerProbe *routehealth.ProbeStore

	runtime serviceimpl.Runtime
}

const (
	defaultCatalogProbeTimeout  = 2 * time.Second
	defaultCatalogReloadTimeout = 30 * time.Second
)

func (o ServiceOptions) catalogProbeTimeout() time.Duration {
	if o.CatalogProbeTimeout > 0 {
		return o.CatalogProbeTimeout
	}
	return defaultCatalogProbeTimeout
}

func (o ServiceOptions) catalogRefreshTimeout() time.Duration {
	if o.CatalogReloadTimeout > 0 {
		return o.CatalogReloadTimeout
	}
	return defaultCatalogReloadTimeout
}

func (s *service) now() time.Time {
	return s.runtime.Now()
}

// lastDecisionEntry caches the most recent RouteDecision for a route key.
type lastDecisionEntry struct {
	decision *RouteDecision
	at       time.Time
}

// loadServiceConfig, when non-nil, is called by New to load a ServiceConfig
// from a directory path when opts.ServiceConfig is nil. It is registered by
// the config package via init() to break the import cycle (config imports root).
var loadServiceConfig func(dir string) (ServiceConfig, error)

// RegisterConfigLoader is called by the config package's init() to install the
// config-loading function. Do not call this from application code.
func RegisterConfigLoader(fn func(dir string) (ServiceConfig, error)) {
	loadServiceConfig = fn
}

// New constructs a FizeauService. When opts.ServiceConfig is nil, New attempts to
// load configuration automatically:
//  1. If opts.ConfigPath is non-empty, load from filepath.Dir(opts.ConfigPath).
//  2. Otherwise, load from the default global config location.
//
// Automatic loading requires the config package to be imported somewhere in the
// binary (it registers the loader via init). If the config package is not
// imported and ServiceConfig is nil, the service starts without provider config
// (ListProviders/HealthCheck will return errors until config is injected).
func New(opts ServiceOptions) (FizeauService, error) {
	if opts.ServiceConfig == nil && loadServiceConfig != nil && shouldAutoLoadServiceConfig(opts) {
		dir := ""
		if opts.ConfigPath != "" {
			dir = filepath.Dir(opts.ConfigPath)
		}
		sc, err := loadServiceConfig(dir)
		if err != nil {
			return nil, fmt.Errorf("agent.New: load config: %w", err)
		}
		opts.ServiceConfig = sc
	}
	svc := &service{
		opts:             opts,
		registry:         harnesses.NewRegistry(),
		harnessInstances: defaultHarnessInstances(),
		hub:              newSessionHub(),
		runtime:          serviceimpl.NewRuntime(serviceimpl.RuntimeDeps{}),
		catalog:          newCatalogCache(catalogCacheOptions{AsyncRefreshTimeout: opts.catalogRefreshTimeout()}),
		routeHealth:      routehealth.NewStore(),
		routeLeases:      routehealth.NewLeaseStore(),
		routeUtilization: routehealth.NewUtilizationStore(),
		routingQuality:   newRoutingQualityStore(),
		providerQuota:    NewProviderQuotaStateStore(),
		providerBurnRate: NewProviderBurnRateTracker(),
	}
	// Hydrate per-provider daily_token_budget from ServiceConfig so the
	// burn-rate tracker can predict exhaustion before the upstream quota
	// signal arrives.
	if opts.ServiceConfig != nil {
		for _, name := range opts.ServiceConfig.ProviderNames() {
			entry, ok := opts.ServiceConfig.Provider(name)
			if !ok {
				continue
			}
			if entry.DailyTokenBudget > 0 {
				svc.providerBurnRate.SetBudget(name, entry.DailyTokenBudget)
			}
		}
	}
	if opts.PersistRouteHealth == "" {
		opts.PersistRouteHealth = defaultRouteHealthPath(opts.ServiceConfig)
	}
	svc.opts = opts
	svc.providerProbe = routehealth.NewProbeStore()
	if opts.PersistRouteHealth != "" {
		_ = svc.providerProbe.Load(opts.PersistRouteHealth)
	}
	startupCtx := opts.QuotaRefreshContext
	if startupCtx == nil {
		startupCtx = context.Background()
	}
	svc.reapStaleHarnessSessions()
	svc.ensurePrimaryQuotaRefresh(startupCtx, quotaRefreshStartup)

	}
	svc := newTestService(t, ServiceOptions{ServiceConfig: sc})

	in := svc.buildRoutingInputs(context.Background())
	providers := providerCostsByName(in, "fiz")
	provider, ok := providers["local"]
	if !ok {
		t.Fatalf("fiz/local provider not in inputs: %#v", providers)
	}
	if got := provider.ContextWindows["small-ctx-model"]; got != 4096 {
		t.Fatalf("ContextWindows[small-ctx-model]=%d, want 4096 (full map=%#v)", got, provider.ContextWindows)
	}
	if got := provider.ContextWindowSources["small-ctx-model"]; got != routing.ContextSourceCatalog {
		t.Fatalf("ContextWindowSources[small-ctx-model]=%q, want %q (full map=%#v)", got, routing.ContextSourceCatalog, provider.ContextWindowSources)
	}
}

// TestResolveRoute_LivenessEscalation exercises the policy→tier ladder
// (cheap → default → smart) wired into ResolveRoute. When every candidate
// at the requested tier is filtered out (here: per-provider context-window
// rejection driven by the catalog), ResolveRoute walks the ladder and
// returns the first higher-tier candidate that still satisfies the request.
// When the entire remaining ladder is also empty, ResolveRoute surfaces
// the precise *ErrNoLiveProvider error rather than the engine's
// "no viable routing candidate" jargon.
func TestResolveRoute_LivenessEscalation(t *testing.T) {
	const fixtureCatalog = `
version: 5
generated_at: 2026-04-25T00:00:00Z
policies:
  default:
    min_power: 5
    max_power: 5
    allow_local: true
  cheap:
    min_power: 5
    max_power: 5
    allow_local: true
  smart:
    min_power: 8
    max_power: 8
    allow_local: true
models:
  medium-model:
    family: tier
    status: active
    power: 5
    context_window: 4096
    surfaces: {agent.openai: medium-model}
  high-model:
    family: tier
    status: active
    power: 8
    context_window: 200000
    surfaces: {agent.openai: high-model}
`

	newSvc := func(t *testing.T) (*service, func()) {
		t.Helper()
		// Block claude/codex/gemini subprocess harnesses from the
		// candidate set so the test isolates the fiz harness's
		// per-provider tier escalation behavior.
		t.Setenv("GEMINI_API_KEY", "")
		t.Setenv("GOOGLE_API_KEY", "")
		t.Setenv("GOOGLE_GENAI_USE_VERTEXAI", "")
		t.Setenv("GOOGLE_GENAI_USE_GCA", "")
		t.Setenv("GEMINI_CLI_USE_COMPUTE_ADC", "")
		t.Setenv("CLOUD_SHELL", "")

		mediumSrv := openAIModelChatServer(t, []string{"medium-model"}, "medium-model", "ok")
		highSrv := openAIModelChatServer(t, []string{"high-model"}, "high-model", "ok")
		catalog := loadRoutingFixtureCatalog(t, fixtureCatalog)
		restore := replaceRoutingCatalogForTest(t, catalog)
		sc := &fakeServiceConfig{
			providers: map[string]ServiceProviderEntry{
				"alpha-medium": {Type: "openai", BaseURL: mediumSrv.URL + "/v1", APIKey: "k", Model: "medium-model"},
				"beta-high":    {Type: "openai", BaseURL: highSrv.URL + "/v1", APIKey: "k", Model: "high-model"},
			},
			names:       []string{"alpha-medium", "beta-high"},
			defaultName: "alpha-medium",
		}
		registry := harnesses.NewRegistry()
		registry.LookPath = func(string) (string, error) { return "", os.ErrNotExist }
		svc := &service{
			opts:     ServiceOptions{ServiceConfig: sc},
			registry: registry,
			hub:      newSessionHub(),
			catalog:  newCatalogCache(catalogCacheOptions{}),
		}
		cleanup := func() {
			mediumSrv.Close()
			highSrv.Close()
			restore()
		}
		return svc, cleanup
	}

	t.Run("escalates_when_lower_tier_filtered_out", func(t *testing.T) {
		svc, cleanup := newSvc(t)
		defer cleanup()

		// Record a route attempt failure on the lower-tier provider so the
		// real cooldown bookkeeping path (applyRouteAttemptCooldowns) runs
		// against this fixture, exercising the AC's "real ServiceConfig +
		// cooldown fixture" requirement.
		if err := svc.RecordRouteAttempt(context.Background(), RouteAttempt{
			Harness:  "fiz",
			Provider: "alpha-medium",
			Model:    "medium-model",
			Status:   "failed",
			Reason:   "synthetic unhealthy fixture",
		}); err != nil {
			t.Fatalf("RecordRouteAttempt: %v", err)
		}

		dec, err := svc.ResolveRoute(context.Background(), RouteRequest{
			Policy:                "default",
			EstimatedPromptTokens: 50_000,
		})
		if err != nil {
			t.Fatalf("ResolveRoute: %v", err)
		}
		if dec == nil || dec.Harness != "fiz" {
			t.Fatalf("decision=%#v, want fiz harness", dec)
		}
		if dec.Provider != "beta-high" {
			t.Fatalf("decision provider=%q, want beta-high (escalated to smart tier)", dec.Provider)
		}
		if dec.Model != "high-model" {
			t.Fatalf("decision model=%q, want high-model", dec.Model)
		}
	})

	t.Run("returns_no_live_provider_when_ladder_exhausted", func(t *testing.T) {
		svc, cleanup := newSvc(t)
		defer cleanup()

		dec, err := svc.ResolveRoute(context.Background(), RouteRequest{
			Policy:                "default",
			EstimatedPromptTokens: 1_000_000, // exceeds both 4096 and 200000 contexts
		})
		if err == nil {
			t.Fatalf("ResolveRoute returned no error, decision=%#v", dec)
		}
		if !strings.Contains(err.Error(), "no live provider") {
			t.Fatalf("error=%q, want 'no live provider' message", err.Error())
		}
		if strings.Contains(err.Error(), "no viable routing candidate") {
			t.Fatalf("error=%q must NOT contain engine 'no viable routing candidate' jargon", err.Error())
		}
		var noLive *ErrNoLiveProvider
		if !errors.As(err, &noLive) {
			t.Fatalf("errors.As ErrNoLiveProvider: %T %v", err, err)
		}
		if noLive.StartingPolicy != "default" {
			t.Fatalf("StartingPolicy=%q, want default", noLive.StartingPolicy)
		}
		if noLive.PromptTokens != 1_000_000 {
			t.Fatalf("PromptTokens=%d, want 1000000", noLive.PromptTokens)
		}
	})
}

